-- ============================================================
--  Migration 041: Add slug to exam_definitions + seed professional exams
--  Fixes: exam start 404/503 by supporting slug-based lookup
-- ============================================================

-- 1. Add slug column to exam_definitions
ALTER TABLE exam_definitions
  ADD COLUMN IF NOT EXISTS slug text;

CREATE UNIQUE INDEX IF NOT EXISTS idx_exam_def_slug ON exam_definitions(slug) WHERE slug IS NOT NULL;

